import numpy as np

class RecallMonitor:
    def __init__(self, eval_queries, exact_ids, k=10, threshold=0.95):
        self.eval_queries = eval_queries  # (Q, d)
        self.exact_ids = exact_ids        # (Q, k) ground truth
        self.k = k
        self.threshold = threshold

    def check(self, index):
        _, I = index.search(self.eval_queries, self.k)
        recall = float(np.mean([
            len(np.intersect1d(I[i], self.exact_ids[i])) / self.k
            for i in range(len(self.eval_queries))
        ]))
        if recall < self.threshold:
            raise RuntimeError(
                f'Recall@{self.k} dropped to {recall:.4f} '
                f'(threshold {self.threshold}). Rebuild index or raise ef.'
            )
        return recall

# Usage: schedule this to run daily against a fixed 1K-query eval set
